import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { getAlbums, deleteAlbum } from '../api/albumService';

export default function AlbumsList(){
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetch = () => { setLoading(true); getAlbums().then(r=>setItems(r.data||[])).catch(()=>{}).finally(()=>setLoading(false)); };
  useEffect(()=>fetch(),[]);

  const handleDelete = (id) => { if(!window.confirm('Supprimer ?')) return; deleteAlbum(id).then(()=>fetch()); };

  return (
    <div>
      <h1>Albums</h1>
      <p><Link to="/albums/create">Créer un album</Link></p>
      {loading ? <div>Chargement...</div> : (
        <ul>
          {items.map(i=> (
            <li key={i.id}>
              <Link to={`/albums/${i.id}`}>{i.titre || i.title || `Album ${i.id}`}</Link>
              {' '}<Link to={`/albums/${i.id}/edit`} style={{marginLeft:8}}>Modifier</Link>
              <button onClick={()=>handleDelete(i.id)} style={{marginLeft:8}}>Supprimer</button>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
